const n = $json.body ?? $json;
return [{
  json: {
    user_id: n.conversationKey || n.channelConversationKey,
    message_id: n.providerMessageId,
    message_type: n.messageType,
    processed_message: n.text || '',
    created_at: n.timestamp,
    processing_priority: 2,
    channel: n.channel
  }
}];

const n = $('webhook').item.json.body ?? {};
const imageAnalysis =
  $json.text ||
  $json.output_text ||
  $json.content?.parts?.[0]?.text ||
  $json.candidates?.[0]?.content?.parts?.[0]?.text ||
  'Görsel analizi yapılamadı';

const caption = n.text || n.media?.[0]?.caption || '';
const processedMessage = `Görsel Analizi:\n${imageAnalysis}` + (caption ? `\n\nKullanıcının mesajı: ${caption}` : '');

return [{
  json: {
    user_id: n.conversationKey || n.channelConversationKey,
    message_id: n.providerMessageId,
    message_type: n.messageType || 'image',
    processed_message: processedMessage,
    created_at: n.timestamp,
    processing_priority: 1,
    channel: n.channel
  }
}];

const n = $('webhook').item.json.body ?? {};
const t = $json.text || $json.transcript || $json.data?.text || 'Ses metne çevrilemedi';

return [{
  json: {
    user_id: n.conversationKey || n.channelConversationKey,
    message_id: n.providerMessageId,
    message_type: n.messageType || 'audio',
    processed_message: `[SES MESAJI]\n\nSes Kaydı İçeriği:\n${t}`,
    created_at: n.timestamp,
    processing_priority: 1,
    channel: n.channel
  }
}];

// Video için basit bir processed message oluştur
// Not: Gemini video analizi için ayrı bir node eklenebilir

const triggerData = $('Switch').item.json;
const message = triggerData.body.entry[0].changes[0].value.messages[0];
const contact = triggerData.body.entry[0].changes[0].value.contacts[0];
const caption = message.video?.caption || '';

const processedMessage = `[VİDEO MESAJI]\n\nKullanıcı bir video gönderdi.${caption ? `\n\nVideo Notu: ${caption}` : ''}`;

return [{
  json: {
    user_id: contact.wa_id,
    message_id: message.id,
    message_type: message.type,
    processed_message: processedMessage,
    created_at: message.timestamp,
    processing_priority: 1
  },
  pairedItem: { item: 0 }
}];

// Document için basit bir processed message oluştur

const triggerData = $('Switch').item.json;
const message = triggerData.body.entry[0].changes[0].value.messages[0];
const contact = triggerData.body.entry[0].changes[0].value.contacts[0];
const fileName = message.document?.filename || 'İsimsiz Dosya';
const caption = message.document?.caption || '';

const processedMessage = `[DÖKÜMAN MESAJI]\n\nDosya Adı: ${fileName}${caption ? `\n\nDosya Notu: ${caption}` : ''}`;

return [{
  json: {
    user_id: contact.wa_id,
    message_id: message.id,
    message_type: message.type,
    processed_message: processedMessage,
    created_at: message.timestamp,
    processing_priority: 1
  },
  pairedItem: { item: 0 }
}];

// =============================================
// INTERACTIVE MESSAGE (LIST REPLY) PROCESSOR
// =============================================

const triggerData = $('Switch').item.json;
const message = triggerData.body.entry[0].changes[0].value.messages[0];
const contact = triggerData.body.entry[0].changes[0].value.contacts[0];

let processedMessage = '[INTERACTIVE MESSAGE]';

// List reply mi?
if (message.interactive?.type === 'list_reply') {
  const listReply = message.interactive.list_reply;

  // JSON string olarak sakla (parse message aggregation'da yapılacak)
  processedMessage = JSON.stringify({
    type: 'list_reply',
    list_reply: {
      id: listReply.id,
      title: listReply.title,
      description: listReply.description || ''
    }
  });
}

// Button reply mi? (gelecekte eklenebilir)
else if (message.interactive?.type === 'button_reply') {
  processedMessage = JSON.stringify({
    type: 'button_reply',
    button_reply: message.interactive.button_reply
  });
}

return [{
  json: {
    user_id: contact.wa_id,
    message_id: message.id,
    message_type: 'interactive',
    processed_message: processedMessage,
    created_at: message.timestamp,
    processing_priority: 2
  },
  pairedItem: { item: 0 }
}];

const items = $input.all();
if (!items.length) return [];

// Webhook fallback (aynı execution'da varsa)
const webhookFallback = (() => {
  try {
    return $('webhook').first()?.json?.body ?? {};
  } catch {
    return {};
  }
})();

const toMs = (v) => {
  if (v == null) return 0;
  if (typeof v === 'number') return v;
  const s = String(v).trim();
  if (!s) return 0;
  if (/^\d+$/.test(s)) {
    const n = Number(s);
    return s.length <= 10 ? n * 1000 : n; // seconds vs milliseconds
  }
  const d = Date.parse(s);
  return Number.isNaN(d) ? 0 : d;
};

const safeParse = (v) => {
  if (typeof v !== 'string') return v;
  try { return JSON.parse(v); } catch { return null; }
};

const typeOf = (m) => m.message_type ?? m.messageType ?? 'text';

const normalized = items.map((row) => {
  const j = row.json ?? {};
  const body = j.body ?? j.webhookBody ?? webhookFallback;
  const key =
    j.conversationKey ??
    j.channelConversationKey ??
    j.user_id ??
    `${j.channel ?? body.channel ?? 'INSTAGRAM'}:${j.channelUserId ?? body.channelUserId ?? j.senderId ?? body.senderId ?? 'unknown'}`;

  return {
    ...j,
    body,
    _key: key,
    _ts: toMs(j.timestamp ?? j.created_at ?? j.eventTimestamp),
  };
}).sort((a, b) => a._ts - b._ts);

// kullanıcı/conversation bazında grupla
const groups = new Map();
for (const m of normalized) {
  if (!groups.has(m._key)) groups.set(m._key, []);
  groups.get(m._key).push(m);
}

function lineFor(msg, i) {
  const t = typeOf(msg);
  const text = msg.processed_message ?? msg.text ?? '';
  let line = `${i + 1}️⃣ `;

  if (t === 'text') return line + `"${text}"`;
  if (t === 'image') return line + '[Görsel]';
  if (t === 'audio') return line + `[Sesli] "${text}"`;
  if (t === 'video') return line + '[Video]';
  if (t === 'document') return line + '[Döküman]';

  if (t === 'interactive') {
    const parsed = safeParse(text);
    if (parsed?.type === 'list_reply' && parsed?.list_reply) {
      return line + `[SEÇİM: ${parsed.list_reply.id}] ${parsed.list_reply.title}`;
    }
  }

  return line + `[${t}]`;
}

const out = [];

for (const [key, msgs] of groups) {
  const first = msgs[0];
  const last = msgs[msgs.length - 1];
  const body = first.body ?? webhookFallback ?? {};

  let combinedMessage = '';
  let isListSelection = false;
  let selectedId = null;

  if (msgs.length === 1 && typeOf(first) === 'interactive') {
    const parsed = safeParse(first.processed_message);
    if (parsed?.type === 'list_reply' && parsed?.list_reply) {
      isListSelection = true;
      selectedId = parsed.list_reply.id;
      combinedMessage = `[SEÇİM: ${parsed.list_reply.id}] ${parsed.list_reply.title}`;
    }
  }

  if (!combinedMessage) {
    if (msgs.length === 1 && typeOf(first) === 'text') {
      combinedMessage = first.processed_message ?? first.text ?? '';
    } else {
      const lines = msgs.map((m, i) => lineFor(m, i));
      combinedMessage = `Kullanıcı ${msgs.length} mesaj gönderdi:\n\n${lines.join('\n')}`;
    }
  }

  out.push({
    json: {
      body, // AI prompt içindeki $json.body.* için gerekli

      salonId: first.salonId ?? body.salonId ?? null,
      channel: first.channel ?? body.channel ?? null,
      conversationKey:
        first.conversationKey ??
        first.channelConversationKey ??
        body.conversationKey ??
        body.channelConversationKey ??
        key,
      canonicalUserId: first.canonicalUserId ?? body.canonicalUserId ?? first.user_id ?? null,
      customerId: first.customerId ?? body.customerId ?? null,
      channelUserId: first.channelUserId ?? body.channelUserId ?? first.senderId ?? body.senderId ?? null,

      user_id: first.user_id ?? null,
      combined_message: combinedMessage,
      message_count: msgs.length,
      has_images: msgs.some((m) => typeOf(m) === 'image'),
      has_audio: msgs.some((m) => typeOf(m) === 'audio'),
      has_video: msgs.some((m) => typeOf(m) === 'video'),
      timestamp_first: first.created_at ?? first.timestamp ?? null,
      timestamp_last: last.created_at ?? last.timestamp ?? null,
      message_ids: msgs.map((m) => m.message_id ?? m.providerMessageId).filter(Boolean),

      is_list_selection: isListSelection,
      selected_id: selectedId,
    },
  });
}

return out;
